steps.content:
{
  "success": true,
  "data": "{
  "database": "ercot_db",
  "query": "SELECT \n  EXTRACT(MONTH FROM timestamp) AS month,\n  COUNT(*) AS hours,\n  AVG(lmp) AS avg_lmp,\n  MIN(lmp) AS min_lmp,\n  MAX(lmp) AS max_lmp\nFROM ercot_lmp \nWHERE zone_name = 'HB_HOUSTON' \n  AND zone_type = 'Hub' \n  AND Is_day_ahead = true \n  AND timestamp >= '2025-01-01' AND timestamp < '2026-01-01'\nGROUP BY month\nORDER BY month",
  "columns": [],
  "row_count": 0,
  "total_rows": 0,
  "truncated": false,
  "rows": []
}",
  "error": null,
  "metadata": {
    "method": "run_query"
  }
}

